import sys
from typing import Optional

class ListNode:
    def __init__(self, val: int = 0, next: Optional['ListNode'] = None):
        self.val = val
        self.next = next

class Solution:
    def length(self, head: Optional[ListNode]) -> int:
        cnt = 0
        cur = head
        while cur:
            cnt += 1
            cur = cur.next
        return cnt

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    n = int(next(it))
    head = None
    tail = None
    for _ in range(n):
        val = int(next(it))
        node = ListNode(val)
        if head is None:
            head = node
            tail = node
        else:
            tail.next = node
            tail = node
    sol = Solution()
    print(sol.length(head))

